import React, {useContext, useMemo} from "react";
import ChartContainer from "../WidgetContainer";
import {generateRadarData} from "../helpers/data";
import {WidgetsContext} from "../context";
import {type IRadarChartProps} from "@lmb-it/kitsconcerto-types";
import {Chart} from "primereact/chart";
import {type ChartOptions} from "chart.js";
import {Skeleton} from "primereact/skeleton";

const RadarChart = () => {
  const {
    isLoading,
    id = Math.random().toString(16).slice(2),
    data: dataProp,
    aspectRatio,
    isDarkMode = false,
  } = useContext(WidgetsContext);

  const { data } = dataProp as IRadarChartProps;

  // const gridLinesColor =
  //         isDarkMode ? 'rgba(255, 255, 255, 0.3)' : 'rgba(0, 0, 0, 0.3)';
  const fontColor = isDarkMode ? "white" : "black";
  // const ticksColor = isDarkMode ? 'white' : 'gray';

  const pieOptions = useMemo(() => {
    return {
      color: fontColor,
      layout: {
        // padding: {
        //     top: 10,
        //     left: 10,
        //     bottom: 10
        // }
      },
      interaction: {
        mode: "index",
        intersect: false,
      },
      cutout: 0,
      maintainAspectRatio: true,
      responsive: true,
      aspectRatio,
      plugins: {
        legend: {
          position: "right" as
            | "right"
            | "top"
            | "bottom"
            | "left"
            | "center"
            | "chartArea",
          labels: {
            usePointStyle: false,
            font: {
              family: "Poppins, Helvetica, sans-serif",
              size: 14,
            },
          },
        },
      },
    } as ChartOptions<"radar">;
  }, [isDarkMode]);

  return (
    <ChartContainer>
      {!isLoading ? (
        <Chart
          type={"radar"}
          id={id}
          options={pieOptions}
          width={"100%"}
          height={"100%"}
          style={{
            justifyContent: "center",
            alignItems: "center",
            display: "flex",
          }}
          // plugins={[plugins.pie(data.datasets.length)]}
          data={generateRadarData(data, isDarkMode)}
        />
      ) : (
        <Skeleton height="100%" width={"100%"} />
      )}
    </ChartContainer>
  );
};

export default RadarChart;
